#include "wombat/services/CpuTemperaturePublisher.h"
#include <fstream>
#include <string>
#include <cmath>

namespace wombat
{
    CpuTemperaturePublisher::CpuTemperaturePublisher(std::shared_ptr<LcmBroker> broker,
                                                     std::shared_ptr<Logger> logger,
                                                     std::chrono::milliseconds publishInterval)
        : broker_{std::move(broker)},
          logger_{std::move(logger)},
          publishInterval_{publishInterval},
          lastPublishTime_{std::chrono::steady_clock::now()}
    {
    }

    Result<void> CpuTemperaturePublisher::initialize()
    {
        if (isInitialized_)
        {
            return Result<void>::success();
        }

        // Verify we can read CPU temperature
        auto tempResult = readCpuTemperature();
        if (tempResult.isFailure())
        {
            logger_->warn("CPU temperature reading failed during initialization: " + tempResult.error());
            logger_->warn("CPU temperature publishing will continue but may not work on this system");
        }
        else
        {
            logger_->info("CPU temperature publisher initialized successfully (current: " + 
                         std::to_string(tempResult.value()) + "°C)");
        }

        isInitialized_ = true;
        lastPublishTime_ = std::chrono::steady_clock::now();
        return Result<void>::success();
    }

    Result<void> CpuTemperaturePublisher::shutdown()
    {
        if (!isInitialized_)
        {
            return Result<void>::success();
        }

        isInitialized_ = false;
        logger_->info("CPU temperature publisher shut down");
        return Result<void>::success();
    }

    Result<void> CpuTemperaturePublisher::update()
    {
        if (!isInitialized_)
        {
            return Result<void>::failure("CPU temperature publisher not initialized");
        }

        // Check if enough time has elapsed since last publish
        auto now = std::chrono::steady_clock::now();
        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(now - lastPublishTime_);

        if (elapsed < publishInterval_)
        {
            // Not time to publish yet
            return Result<void>::success();
        }

        // Read CPU temperature
        auto tempResult = readCpuTemperature();
        if (tempResult.isFailure())
        {
            logger_->debug("Failed to read CPU temperature: " + tempResult.error());
            return Result<void>::failure("Failed to read CPU temperature: " + tempResult.error());
        }

        float temperature = tempResult.value();

        // Log the temperature reading
        logger_->debug("CPU temperature read: " + std::to_string(temperature) + "°C");

        // Publish the temperature
        auto publishResult = publishTemperature(temperature);
        if (publishResult.isFailure())
        {
            logger_->warn("Failed to publish CPU temperature: " + publishResult.error());
            return publishResult;
        }

        // Update last publish time and value
        lastPublishTime_ = now;
        lastPublishedTemperature_ = temperature;

        logger_->debug("CPU temperature published: " + std::to_string(temperature) + "°C");

        return Result<void>::success();
    }

    Result<float> CpuTemperaturePublisher::readCpuTemperature()
    {
        // Read from Linux thermal zone (temperature in millidegrees Celsius)
        const std::string thermalPath = "/sys/class/thermal/thermal_zone0/temp";

        std::ifstream thermalFile(thermalPath);
        if (!thermalFile.is_open())
        {
            return Result<float>::failure("Unable to open thermal sensor file: " + thermalPath);
        }

        std::string tempStr;
        std::getline(thermalFile, tempStr);
        thermalFile.close();

        if (tempStr.empty())
        {
            return Result<float>::failure("Empty temperature reading from thermal sensor");
        }

        try
        {
            // Convert from millidegrees to degrees Celsius
            int milliTemp = std::stoi(tempStr);
            float temperature = static_cast<float>(milliTemp) / 1000.0f;

            // Sanity check: CPU temperature should be between -40°C and 125°C
            if (temperature < -40.0f || temperature > 125.0f)
            {
                return Result<float>::failure("CPU temperature out of valid range: " + std::to_string(temperature));
            }

            return Result<float>::success(temperature);
        }
        catch (const std::exception& e)
        {
            return Result<float>::failure("Failed to parse temperature value: " + std::string(e.what()));
        }
    }

    Result<void> CpuTemperaturePublisher::publishTemperature(float temperature)
    {
        // Convert to LCM message format
        auto message = convertScalarF(temperature);

        // Publish on the CPU temperature channel
        auto result = broker_->publishScalarF(Channels::CPU_TEMPERATURE, message);
        if (result.isFailure())
        {
            return Result<void>::failure("Failed to publish CPU temperature: " + result.error());
        }

        return Result<void>::success();
    }

    exlcm::scalar_f_t CpuTemperaturePublisher::convertScalarF(float value) const
    {
        exlcm::scalar_f_t message{};
        message.value = value;
        return message;
    }

} // namespace wombat

